import contextlib
import typing

ExceptionMapping = typing.Mapping[typing.Type[Exception], typing.Type[Exception]]


@contextlib.contextmanager
def map_exceptions(map: ExceptionMapping) -> typing.Iterator[None]:
    """Context manager that maps raised exceptions to other exception types.

    Any exception raised inside the context that is an instance of one of the
    keys in `map` will be re-raised as the corresponding mapped exception
    type, with the original exception attached as the __cause__.

    Parameters:
    - map: A mapping from exception types to exception types. If an exception
      raised inside the context is an instance of a key type, it will be
      converted to the corresponding value type.

    Example:
        with map_exceptions({ValueError: RuntimeError}):
            raise ValueError("bad")

        # This will raise RuntimeError(ValueError("bad")) from ValueError("bad")
    """
    try:
        yield
    except Exception as exc:  # noqa: PIE786
        for from_exc, to_exc in map.items():
            if isinstance(exc, from_exc):
                raise to_exc(exc) from exc
        raise  # pragma: nocover


class ConnectionNotAvailable(Exception):
    pass


class ProxyError(Exception):
    pass


class UnsupportedProtocol(Exception):
    pass


class ProtocolError(Exception):
    pass


class RemoteProtocolError(ProtocolError):
    pass


class LocalProtocolError(ProtocolError):
    pass


# Timeout errors


class TimeoutException(Exception):
    pass


class PoolTimeout(TimeoutException):
    pass


class ConnectTimeout(TimeoutException):
    pass


class ReadTimeout(TimeoutException):
    pass


class WriteTimeout(TimeoutException):
    pass


# Network errors


class NetworkError(Exception):
    pass


class ConnectError(NetworkError):
    pass


class ReadError(NetworkError):
    pass


class WriteError(NetworkError):
    pass